      function CF_15Formula return Char is

V_START_DATE		DATE;
V								VARCHAR2(25);

begin
	
	SELECT START_DATE
	INTO V_START_DATE
  FROM PEN_ACCOUNT
  WHERE Account_No =  :P_Acc_Account_No;

  IF V_START_DATE >= TO_DATE('15072010','DDMMRRRR') THEN
  	V := '16 Ν.3863/10';
  ELSE 
  	V:= :DECODE_WORK_INS_SECTOR_Ι_63_Ν_;
  END IF;
  
  RETURN V;
  
end;

      function CF_16Formula return Char is

V	VARCHAR2(6);

begin
  
  
  IF :SECTOR = 'Α' THEN 
  	V := '100%';
  ELSE
  	V := '70%';
  END IF;
  
  :CP_2 := ',ΝΑ ΓΙΝΕΙ ΜΕΙΩΣΗ ΚΑΤΑ '||V;
  
  RETURN V;
  
end;

      function CF_17Formula return Char is

V_START_DATE		DATE;
V								VARCHAR2(60);
v_limit_amount_for_excess		NUMBER;
v_number_of_HAE							NUMBER;
V_Single_Wages_Triennium0		NUMBER;

cursor cur_limit_amnt is
select limit_amount_for_excess,
       number_of_HAE,
       Single_Wages_Triennium0
from PEN_ACCOUNT_WORKING_INFO
where ACCOUNT_NO = :P_Acc_Account_No;

begin
	
	SELECT START_DATE
	INTO V_START_DATE
  FROM PEN_ACCOUNT
  WHERE Account_No =  :P_Acc_Account_No;

  IF V_START_DATE >= TO_DATE('15072010','DDMMRRRR') THEN
  	
  	IF :SECTOR IN ('Ι','Α') THEN
  		open cur_limit_amnt;
  		fetch cur_limit_amnt
  		into v_limit_amount_for_excess,
  				 v_number_of_HAE,
  				 V_Single_Wages_Triennium0;
  		close cur_limit_amnt;
  		V:= 'ΣΤΟ ΠΟΣΟ ΠΟΥ ΥΠΕΡΒΑΙΝΕΙ ΤΑ '||v_number_of_HAE||'ΗΑΕ x'||V_Single_Wages_Triennium0||'='||v_limit_amount_for_excess||' ΕΥΡΩ';	  		
  	ELSIF :SECTOR = 'Δ' THEN
  		V := 'ΣΤΟ ΣΥΝΟΛΙΚΟ ΠΟΣΟ ΤΗΣ ΣΥΝΤΑΞΗΣ';  	
  	END IF;
  	
  ELSE 
  	V := :DECODE_WORK_INS_SECTOR_Ι_ΣΤΟ_Π;
  END IF;
  
  RETURN V;
  
end;

      function CF_18Formula return Char is
v  varchar2(20);

begin
  
  v := '( '||:initial_amount||' x 70% )';
  
  return v;
  
end;

      function CF_announce_employment_textFor return Char is

V_START_DATE		DATE;
v_text			varchar2(200);

begin

	SELECT START_DATE
	INTO V_START_DATE
  FROM PEN_ACCOUNT
  WHERE Account_No =  :P_Acc_Account_No;

  IF V_START_DATE >= TO_DATE('15072010','DDMMRRRR') THEN  
  		v_text := 'Ο χρόνος απασχόλησης μετά τη συνταξιοδότηση είναι συντάξιμος.
(περ.3 παρ.1 άρθρο 16 Ν.3863/10)';
  ELSE
  	  v_text := 'Ο χρόνος απασχόλησης μετά τη συνταξιοδότηση χωρίς αναστολή σύνταξης, δεν είναι συντάξιμος.
(άρθρο 63 Ν.2676/99)';
  END IF;
  
return v_text;
  
end;

      function CF_soixeia_paymentsFormula return Char is

to_return varchar2(500);
v_iban      varchar2(60);

cursor Cur_Fact_Subtype_Existance IS 
  select distinct pen_dec_fact_types_instance.value
  from  pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code='01069' AND 
pen_dec_fact_types_instance.ins_insured_id= :p_INSURED_ID AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
