FROM  PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO;


begin
  
  OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  
  RETURN (NVL(V_NUM,0)*NVL(V_NUM_1,0))/100;
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

