CURSOR cur_amount_2 IS
SELECT MONTHS_GAP
FROM PEN_ACCOUNT_AGE_REDUCTION
WHERE ACCOUNT_NO =  :P_ACC_ACCOUNT_NO;
-- END CHRYS 8/11/2019


begin
  V_AMOUNT := NVL(TO_NUMBER(:P_MONTHS_200),0);
  -- CHRYS 8/11/2019
  	OPEN cur_amount_2;
  	FETCH cur_amount_2
  	INTO v_amount_2;
