      function M_3FormatTrigger return boolean is
v_product        varchar2(5);
v_DOUBT_FLG      varchar2(1);

cursor cur_product is
  SELECT PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE
  FROM PEN_QC_PER_PRODINST, 
       PEN_PRODUCT_PER_INSTITUTIONS
 WHERE PEN_QC_PER_PRODINST.QC_PER_PRODINST_CODE=:P_QC_PER_PRODINST
   AND PEN_QC_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE;

cursor cur_flg is
SELECT DOUBT_FLG
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO;

begin
    
    open cur_product;
    fetch cur_product
    into v_product;
    close cur_product;
    
    open cur_flg;
    fetch cur_flg
    into v_DOUBT_FLG;
    close cur_flg;
    
 -- CHRYS 19/10/2018 if v_product = '00002' and v_DOUBT_FLG = '1'  then
  	if v_DOUBT_FLG = '1'  then -- CHRYS 19/10/2018
  
      return (TRUE);
  else
      return (FALSE);
  end if;
  
end;

