      function B_27FormatTrigger return boolean is


CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG, AFTER_01_10_2019_FLG 
FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_01_01_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;
V_01_10_2019    PEN_INTRODUCTIONS.AFTER_01_10_2019_FLG%TYPE;


begin

  OPEN  CUR_2019;
  FETCH CUR_2019 INTO V_01_01_2019,V_01_10_2019;
	CLOSE CUR_2019;
	
	-- ΑΝ ΕΧΕΙ 9ΑΔΕΣ ΜΕ ΠΛΑΦΟΝ ΚΡΥΨΕ
	IF NVL(:P_CP9,0) > 0 THEN 
	  return (FALSE);
	ELSE
	  IF ( NVL(V_01_01_2019,'0') = '1'  OR NVL(V_01_10_2019,'0') = '1'  OR :cf_35 in ('00010') ) THEN
	  	return (FALSE);
	  ELSE
	  	return (TRUE);
	  END IF;
  END IF;

  return (TRUE);

end;

