      function F_29FormatTrigger return boolean is


V_STRING VARCHAR2(500);
v_descr  VARCHAR2(500); 
  
Cursor c1 Is  
Select upper(A.Award_Descr)
From Pen_Award_Type_Flag_Desc A,
     Wrk_In_Out B
Where A.Document_Code        = B.Document_Code
  And B.Protocol_Orgbra_Code = :P_APPL_UNIT_CODE
  And B.Protocol_Year        = :P_APPL_YEAR
  And B.Protocol_No          = :P_APPL_INCR_SEQ_NO
;  

  
begin
  
  Open c1;
    Fetch c1 Into v_descr;
  Close c1;
  --
	if :cp_award_type='8' then
		IF :CP_DOC_TROP ='006' THEN
     V_STRING := '(ΤΡΟΠΟΠΟΙΗΤΙΚΗ)' ; 
     srw.set_field_char(0, V_STRING);
		ELSE
		 V_STRING := v_descr;---'(ΑΝΑΘΕΩΡΗΤΙΚΗ)' ; 08/12/2020 email by AMETAXA spap 
     srw.set_field_char(0, V_STRING);
		END IF;	
    return (TRUE);
	else
		return false;
	end if;
	
	end;

