      function R_7FormatTrigger return boolean is
  V_TEXT VARCHAR2(50);
  V_EXISTS NUMBER;
  
  cursor cur_childincr is
  SELECT 1
  FROM PEN_QT_PER_BE_CC_PER_ACCOUNT A
	WHERE A.DI_DT_DOCUMENT_TYPE_DEC_CODE = '1'
	AND A.DI_DT_DEC_UNIT_CODE = :P_DT_DEC_UNIT_CODE
	AND A.DI_DT_DECISION_YEAR = :P_DT_DECISION_YEAR
	AND A.DI_DEC_INCR_SEQ_NO = :P_DEC_INCR_SEC_NO_SR
	and A.ins_insured_id = :INDIRECT_ID
	AND A.CC_PER_BE_TYPE_PER_DECINS_UPD = '1'
	AND A.STATUS='1';

begin
	
   OPEN cur_childincr;
   FETCH cur_childincr
   INTO V_EXISTS;
   CLOSE cur_childincr;
     

   V_TEXT := Find_Fact_Sub_Death_Varchar(:INDIRECT_ID,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
			 0,:p_form_id,'00003','00013','00019');

 IF v_text is not null aND V_EXISTS =1 then  
   return (TRUE);
 else
 	 return false;
 end if;
end;

