-- CHRYS 8/11/2019
V_amount NUMBER;

CURSOR cur_amount_2 IS
SELECT MONTHS_GAP
FROM PEN_ACCOUNT_AGE_REDUCTION
WHERE ACCOUNT_NO =  :P_ACC_ACCOUNT_NO;
-- END CHRYS 8/11/2019


begin
  -- CHRYS 8/11/2019
  IF v_amount IS NULL THEN
  	OPEN cur_amount_2;
  	FETCH cur_amount_2
  	INTO v_amount;
  	CLOSE cur_amount_2;
  END IF;	
  -- END CHRYS 8/11/2019

  IF (:P_MONTHS_200 LIKE '0%' OR :P_MONTHS_200 IS NULL)
  	AND V_AMOUNT IS NULL THEN -- CHRYS 8/11/2019
  	RETURN (FALSE);
  ELSE
  	RETURN (TRUE);
  END IF;
  
end;

