cursor c_fact_date is
select a.factitious_application_date 
from pen_decision_instance a
where 1=1
and   a.dt_dec_unit_code = :P_DT_DEC_UNIT_CODE
and   a.dt_decision_year = :P_DT_DECISION_YEAR
and   a.dec_incr_seq_no   = :P_DEC_INCR_SEC_NO
;

l_date Date;

begin
  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019 - Η ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/10/2019
  V_01_01_2019 := '0';
  V_01_10_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019 INTO V_01_01_2019,V_01_10_2019;
	CLOSE CUR_2019;
	  
	OPEN  c_fact_date;
  FETCH c_fact_date INTO l_date;
	CLOSE c_fact_date;
	  
--	srw.message(100,' :CF_35   : '||:CF_35 );
--	srw.message(100,' V_01_01_2019'||V_01_01_2019);
--	srw.message(100,' V_01_10_2019'||V_01_10_2019);
	
	  
  IF ( ( NVL(V_01_01_2019,'0') = '1' OR NVL(V_01_10_2019,'0') = '1' ) ) --OR (:CF_35='00008' AND l_date >= TO_DATE('01/01/2019','DD/MM/YYYY'))
  	THEN
  	return (FALSE);
  ELSE
  	return (TRUE);
  END IF;

  return (TRUE);
end;

