begin
  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019 - Η ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/10/2019 ΝΑ ΕΜΦΑΝΙΖΕΤΑΙ ΜΟΝΟ ΑΥΤΟ ΤΟ ΚΟΜΜΑΤΙ ΤΕΛΙΚΑ 17/09/2021 ΑΠΟ MAIL 15/09/2021 ZKOYTPA
  V_01_01_2019 := '0';
  V_01_10_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019 INTO V_01_01_2019,V_01_10_2019;
	CLOSE CUR_2019;
	
	  
  IF ( ( NVL(V_01_01_2019,'0') = '1' OR NVL(V_01_10_2019,'0') = '1' ) ) 
  	THEN
  	return (TRUE);
  ELSE
  	return (FALSE);
  END IF;

end;

