      function CF_PLAFONFormula return Number is

V_PLAFON		NUMBER;
CURSOR	CUR_PLAFON IS
SELECT AMOUNT
FROM   PEN_QT_PER_BE_CC_PER_ACCOUNT A,
			 PEN_ACCOUNT B
WHERE  B.ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND    B.ACCOUNT_NO = A.ACC_ACCOUNT_NO
AND    A.CP_CALCULATION_PARAMETER_CODE = 'PLAFN';
			 
begin

OPEN	CUR_PLAFON;
FETCH	CUR_PLAFON
INTO	V_PLAFON;
CLOSE	CUR_PLAFON;

RETURN (NVL(V_PLAFON,0));


end;

      function CF_55Formula return Number is
v_NUM NUMBER;
-- CHRYS 3/6/2021    
CURSOR 	CUR_AMOUNT_DIAFR IS
SELECT 	AMOUNT
FROM 		PEN_QT_PER_BE_CC_PER_ACCOUNT
WHERE	 	ACC_ACCOUNT_NO =:P_ACC_ACCOUNT_NO
AND			CP_CALCULATION_PARAMETER_CODE = 'DIAFR'
AND     CC_PER_BE_TYPE_PER_DECINS_UPD = '1';   

begin
	OPEN 	CUR_AMOUNT_DIAFR;
	FETCH CUR_AMOUNT_DIAFR
  INTO 	v_NUM;
  CLOSE CUR_AMOUNT_DIAFR;
                  
  RETURN v_NUM;
END ;

      function CF_51Formula return Number is
v_NUM NUMBER;
    
    CURSOR Cur_NUM IS
   SELECT NVL(PERSONAL_DIFFERENCE,0)
FROM PEN_EFKA_PERSONAL_DIFFERENCE
WHERE ACCOUNT_NO =:P_ACC_ACCOUNT_NO;   

begin
  
  
                 OPEN Cur_NUM;
                  FETCH Cur_NUM
                  INTO v_NUM;
                  CLOSE Cur_NUM;
                  
             RETURN v_NUM;
END ;

